import React from 'react';
import { Mail, Phone, MapPin, Globe, Linkedin, Github } from 'lucide-react';

const LeetCodeIcon = ({ size = 14 }) => (
  <svg xmlns="http://www.w3.org/2000/svg" width={size} height={size} viewBox="0 0 24 24" fill="none" stroke="currentColor" strokeWidth="2.5" strokeLinecap="round" strokeLinejoin="round">
    <polyline points="16 18 22 12 16 6" />
    <polyline points="8 6 2 12 8 18" />
    <line x1="12" y1="9" x2="10" y2="15" />
  </svg>
);

const RezumeTemplate = ({ data }) => {
  const { personalInfo, education, experience, projects, skills, sectionTitles } = data;

  return (
    <div id="resume-template" className="rezume-container">
      {/* Header */}
      <header className="rezume-header">
        <h1 className="name">{personalInfo.fullName.toUpperCase()}</h1>

        <div className="contact-grid">
          <div className="contact-left">
            <div className="contact-item">
              <Globe size={12} />
              <a href={`https://${personalInfo.github}`} target="_blank" rel="noreferrer">portfolio.me</a>
            </div>
            <div className="contact-item social-links">
              <a href={`https://${personalInfo.linkedin}`} target="_blank" rel="noreferrer"><Linkedin size={12} /></a>
              <a href={`https://${personalInfo.github}`} target="_blank" rel="noreferrer"><Github size={12} /></a>
              {personalInfo.leetcode && (
                <a href={personalInfo.leetcode.startsWith('http') ? personalInfo.leetcode : `https://${personalInfo.leetcode}`} target="_blank" rel="noreferrer">
                  <LeetCodeIcon size={12} />
                </a>
              )}
            </div>
          </div>

          <div className="contact-right">
            <div className="contact-item">
              <MapPin size={12} />
              <span>{personalInfo.location || 'City, State, Country'}</span>
            </div>
            <div className="contact-item">
              <Mail size={12} />
              <a href={`mailto:${personalInfo.email}`}>{personalInfo.email}</a>
              <span className="separator">|</span>
              <Phone size={12} />
              <a href={`tel:${personalInfo.phone.replace(/[^0-9+]/g, '')}`}>{personalInfo.phone}</a>
            </div>
          </div>
        </div>
      </header>

      {/* Education */}
      <section className="section">
        <h2 className="section-title">{sectionTitles?.education?.toUpperCase() || 'EDUCATION'}</h2>
        <div className="title-line"></div>
        {education.map((edu, index) => (
          <div key={index} className="item">
            <div className="item-row">
              <span className="bold">{edu.school}</span>
              <span className="date">{edu.date}</span>
            </div>
            <div className="item-row sub">
              <span className="italic">{edu.degree}</span>
              <span className="italic">{edu.location}</span>
            </div>
          </div>
        ))}
      </section>

      {/* Experience */}
      <section className="section">
        <h2 className="section-title">{sectionTitles?.experience?.toUpperCase() || 'EXPERIENCE'}</h2>
        <div className="title-line"></div>
        {experience.map((exp, index) => (
          <div key={index} className="item">
            <div className="item-row">
              <span className="bold">{exp.role}</span>
              <span className="date">{exp.date}</span>
            </div>
            <div className="item-row sub">
              <span className="italic">{exp.company}</span>
              <span className="italic">{exp.location}</span>
            </div>
            <ul className="bullets">
              {exp.bullets.map((bullet, i) => (
                <li key={i}>{bullet}</li>
              ))}
            </ul>
          </div>
        ))}
      </section>

      {/* Projects */}
      {projects && projects.length > 0 && (
        <section className="section">
          <h2 className="section-title">{sectionTitles?.projects?.toUpperCase() || 'PROJECTS'}</h2>
          <div className="title-line"></div>
